#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;

# Supposons que nous voulons extraire l'auteur d'un PDF.
# Notre mission est de trouver le nom de l'auteur dans le PDF.

sub extraire_auteur {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    # Parcourons chaque page du PDF
    for my $page (1 .. $pdf->pages) {
        my $text = $pdf->page($page)->text;
        if ($text =~ /Auteur : (.+)/i) {
            return $1;
        }
    }

    return "Auteur inconnu";
}

# Utilisation du script
my $auteur = extraire_auteur('mon_document.pdf');
print "L'auteur est : $auteur\n";

# Et maintenant, une petite touche de francité!
print "Bonne lecture, mon ami! N'oublie pas de bien vérifier tes informations avant de les publier.\n";
